content.content:
1	/**
2	 * lab.guild-setup / lab.guild-teardown — fixture engines for a per-trial
3	 * test guild.
4	 *
5	 * MOTIVATION
6	 * ──────────
7	 * A trial wants a fresh, disposable guild instance to commission work
8	 * into. The guild needs:
9	 *   - The right plugins installed (varies per trial: every plugin the
10	 *     test workload exercises must be there).
11	 *   - The codexes from upstream fixtures registered (so the test guild
12	 *     knows about them).
13	 *   - Optional `guild.json` overlay (e.g. configuring patron role for
14	 *     astrolabe).
15	 *   - Optional file copies (e.g. a custom prompt template for animator).
16	 *
17	 * SETUP FLOW
18	 * ──────────
19	 * 1. Validate givens; resolve guildName, guildPath, frameworkVersion.
20	 * 2. Refuse if the target dir already exists (idempotency / safety).
21	 * 3. **Bootstrap (one-time, npx):**
22	 *    `npx -p @shardworks/nexus@<frameworkVersion> nsg init <guildPath>
23	 *    --name <guildName>`. This mirrors how a real user would create a
24	 *    guild from scratch and binds the test guild to the trial-pinned
25	 *    framework version (the version-true `init` runs against the
26	 *    version-true `VERSION` constant). After bootstrap,
27	 *    `<guildPath>/node_modules/.bin/nsg` exists.
28	 * 4. For each plugin pin: `<guildPath>/node_modules/.bin/nsg
29	 *    --guild-root <guildPath> plugin install <name>@<version>`.
30	 * 5. Discover codexes from `context.upstream`: any upstream yields with
31	 *    `codexName` + `remoteUrl` (the codex-fixture's yields shape) get
32	 *    registered via the test guild's local nsg. Walks all upstream
33	 *    entries — no manifest-level dependsOn declaration of "this is
34	 *    the codex" needed.
35	 * 6. Deep-merge `givens.config` into `<guildPath>/guild.json`.
36	 * 7. Copy each `givens.files[]` entry from `sourcePath` (absolute only
37	 *    in v1) to `<guildPath>/<guildPath>` (per-entry guildPath).
38	 * 8. Yield guildPath, pluginsResolved, codexesAdded, filesCopied.
39	 *
40	 * After bootstrap (step 3), the lab-host's `nsg` is **not** invoked
41	 * again for this trial. Steps 4-5 use the test guild's locally-
42	 * installed CLI; the scenario engine (commission-post-xguild) and
43	 * its sibling do the same. The lab-host doesn't need a global or
44	 * local `nsg` install for the laboratory to work — only `npx` (which
45	 * ships with Node).
46	 *
47	 * Failure handling: any error mid-setup triggers best-effort rollback
48	 * (rm -rf the guild dir) and re-throws.
49	 *
50	 * TEARDOWN FLOW
51	 * ─────────────
52	 * 1. Validate givens; resolve guildPath.
53	 * 2. Archive-safety check (same as codex-teardown).
54	 * 3. `rm -rf <guildPath>`.
55	 * 4. Yield `{ removed: true, guildPath }`.
56	 *
57	 * GIVENS (setup AND teardown — fixture givens are shared)
58	 * ───────────────────────────────────────────────────────
59	 *   guildName : string?  — Optional. The test guild's identity name.
60	 *                          Defaults to `<slug>-<writId-tail>` from the
61	 *                          framework-injected `_trial` context (matches
62	 *                          the codex-fixture's default-naming convention).
63	 *   guildPath : string?  — Optional. Absolute path for the test guild dir.
64	 *                          Defaults to
65	 *                          `<labHostGuild>/.nexus/laboratory/guilds/<guildName>/`.
66	 *   plugins   : Array<{name, version}>?  — Optional. Plugin pins to install.
67	 *                          Each entry is shelled out as
68	 *                          `nsg plugin install <name>@<version>` against the
69	 *                          test guild's local nsg. **Versions must be stable
70	 *                          pins** (exact semver, git+url#sha, github-shorthand
71	 *                          #sha, or registry tarball) — the manifest CLI
72	 *                          rejects file:/link:/range/dist-tag forms at load
73	 *                          time, see `stable-pin.ts`.
74	 *   config    : object?   — Optional. Deep-merged into the guild's
75	 *                          `guild.json` after init.
76	 *   files     : Array<{sourcePath, guildPath}>?  — Optional. File copies.
77	 *                          sourcePath must be absolute in v1 (throws on
78	 *                          relative). guildPath is relative to the guild
79	 *                          root.
80	 *
81	 * YIELDS (setup)
82	 * ──────────────
83	 *   {
84	 *     guildName: string,
85	 *     guildPath: string,
86	 *     pluginsResolved: Array<{ name: string; version: string }>,
87	 *     codexesAdded: Array<{ codexName: string; remoteUrl: string }>,
88	 *     filesCopied: Array<{ sourcePath: string; guildPath: string }>,
89	 *   }
90	 *
91	 * YIELDS (teardown)
92	 * ─────────────────
93	 *   { removed: true, guildName: string, guildPath: string }
94	 */
95	
96	import { execFile as execFileCb } from 'node:child_process';
97	import { promisify } from 'node:util';
98	import { existsSync } from 'node:fs';
99	import { copyFile, mkdir, readFile, rm, writeFile } from 'node:fs/promises';
100	import path from 'node:path';
101	import { guild } from '@shardworks/nexus-core';
102	import type {
103	  EngineDesign,
104	  EngineRunContext,
105	  EngineRunResult,
106	} from '@shardworks/fabricator-apparatus';
107	import type { InjectedTrialContext } from './phases.ts';
108	import {
109	  assertArchiveRowExists,
110	  resolveTrialIdForTeardown,
111	} from '../archive/presence.ts';
112	
113	const execFile = promisify(execFileCb);
114	
115	// ── Givens validation ────────────────────────────────────────────────
116	
117	export interface PluginPin {
118	  name: string;
119	  version: string;
120	}
121	
122	export interface FileCopy {
123	  sourcePath: string;
124	  guildPath: string;
125	}
126	
127	interface ResolvedGuildFixtureGivens {
128	  guildName: string;
129	  guildPath: string;
130	  plugins: PluginPin[];
131	  config: Record<string, unknown>;
132	  files: FileCopy[];
133	  frameworkVersion?: string;
134	}
135	
136	/**
137	 * Guild-name rules — used as the test guild's `name` field and as the
138	 * default dir basename. Conservative: kebab-case, 1–60 chars.
139	 */
140	const GUILD_NAME_PATTERN = /^[a-z][a-z0-9-]{0,59}$/;
141	
142	/**
143	 * Compute the default guild name from the framework-injected `_trial`
144	 * context: `<slug>-<writIdTail>`. Returns null when `_trial` is missing
145	 * or malformed.
146	 */
147	function defaultGuildName(givens: Record<string, unknown>): string | null {
148	  const trial = givens._trial as InjectedTrialContext | undefined;
149	  if (!trial || typeof trial.slug !== 'string' || typeof trial.writId !== 'string') {
150	    return null;
151	  }
152	  const tail = (trial.writId.split('-').pop() ?? trial.writId).slice(0, 8);
153	  return `${trial.slug}-${tail}`;
154	}
155	
156	/**
157	 * Resolve the default guild path inside the lab-host guild's filesystem.
158	 * Mirrors the codex-fixture's `.nexus/laboratory/codexes/<name>.git`
159	 * placement: lab-host-internal, namespaced under `.nexus/laboratory/`.
160	 */
161	export function defaultGuildPath(labHostGuildHome: string, guildName: string): string {
162	  return path.join(labHostGuildHome, '.nexus', 'laboratory', 'guilds', guildName);
163	}
164	
165	function validateGivens(
166	  rawGivens: Record<string, unknown>,
167	  designId: string,
168	): ResolvedGuildFixtureGivens {
169	  // Resolve guildName.
170	  let guildName = rawGivens.guildName;
171	  if (guildName === undefined || guildName === null) {
172	    const fallback = defaultGuildName(rawGivens);
173	    if (fallback === null) {
174	      throw new Error(
175	        `[${designId}] givens.guildName is missing and no _trial context was injected. ` +
176	          `Either author guildName explicitly, or ensure the engine runs under the ` +
177	          `Laboratory phase orchestrators.`,
178	      );
179	    }
180	    guildName = fallback;
181	  }
182	  if (typeof guildName !== 'string' || !GUILD_NAME_PATTERN.test(guildName)) {
183	    throw new Error(
184	      `[${designId}] guildName must be kebab-case (start with a letter; ` +
185	        `alphanumeric and hyphens; ≤60 chars); got "${String(guildName)}".`,
186	    );
187	  }
188	
189	  // Resolve guildPath.
190	  let guildPath = rawGivens.guildPath;
191	  if (guildPath === undefined || guildPath === null) {
192	    guildPath = defaultGuildPath(guild().home, guildName);
193	  }
194	  if (typeof guildPath !== 'string' || !path.isAbsolute(guildPath)) {
195	    throw new Error(
196	      `[${designId}] guildPath must be an absolute path; got "${String(guildPath)}".`,
197	    );
198	  }
199	
200	  // Plugins.
201	  const rawPlugins = rawGivens.plugins ?? [];
202	  if (!Array.isArray(rawPlugins)) {
203	    throw new Error(
204	      `[${designId}] givens.plugins must be an array of {name, version}; got ` +
205	        `${typeof rawPlugins}.`,
206	    );
207	  }
208	  const plugins: PluginPin[] = [];
209	  for (let i = 0; i < rawPlugins.length; i += 1) {
210	    const p = rawPlugins[i] as Record<string, unknown> | undefined;
211	    if (!p || typeof p.name !== 'string' || typeof p.version !== 'string') {
212	      throw new Error(
213	        `[${designId}] givens.plugins[${i}] must be {name: string, version: string}; ` +
214	          `got ${JSON.stringify(p)}.`,
215	      );
216	    }
217	    plugins.push({ name: p.name, version: p.version });
218	  }
219	
220	  // Config.
221	  const rawConfig = rawGivens.config ?? {};
222	  if (!isPlainObject(rawConfig)) {
223	    throw new Error(
224	      `[${designId}] givens.config must be a plain object; got ${typeof rawConfig}.`,
225	    );
226	  }
227	
228	  // Files.
229	  const rawFiles = rawGivens.files ?? [];
230	  if (!Array.isArray(rawFiles)) {
231	    throw new Error(
232	      `[${designId}] givens.files must be an array of {sourcePath, guildPath}; got ` +
233	        `${typeof rawFiles}.`,
234	    );
235	  }
236	  const files: FileCopy[] = [];
237	  for (let i = 0; i < rawFiles.length; i += 1) {
238	    const f = rawFiles[i] as Record<string, unknown> | undefined;
239	    if (!f || typeof f.sourcePath !== 'string' || typeof f.guildPath !== 'string') {
240	      throw new Error(
241	        `[${designId}] givens.files[${i}] must be {sourcePath: string, guildPath: string}; ` +
242	          `got ${JSON.stringify(f)}.`,
243	      );
244	    }
245	    if (!path.isAbsolute(f.sourcePath)) {
246	      throw new Error(
247	        `[${designId}] givens.files[${i}].sourcePath must be absolute in v1 ` +
248	          `(manifest-relative resolution is future work); got "${f.sourcePath}".`,
249	      );
250	    }
251	    if (path.isAbsolute(f.guildPath)) {
252	      throw new Error(
253	        `[${designId}] givens.files[${i}].guildPath must be relative to the guild root; ` +
254	          `got absolute "${f.guildPath}".`,
255	      );
256	    }
257	    files.push({ sourcePath: f.sourcePath, guildPath: f.guildPath });
258	  }
259	
260	  // Pull frameworkVersion from the framework-injected _trial context.
261	  // trial-post.ts resolves an undefined manifest value before stamping
262	  // the writ, so on a posted trial this should always be set —
263	  // teardown calls don't need it (we early-return here for
264	  // teardown).
265	  const trial = rawGivens._trial as InjectedTrialContext | undefined;
266	  const frameworkVersion =
267	    trial && typeof trial.frameworkVersion === 'string' && trial.frameworkVersion.length > 0
268	      ? trial.frameworkVersion
269	      : undefined;
270	
271	  return { guildName, guildPath, plugins, config: rawConfig, files, frameworkVersion };
272	}
273	
274	// ── Helpers ──────────────────────────────────────────────────────────
275	
276	function isPlainObject(v: unknown): v is Record<string, unknown> {
277	  return (
278	    typeof v === 'object' &&
279	    v !== null &&
280	    !Array.isArray(v) &&
281	    Object.getPrototypeOf(v) === Object.prototype
282	  );
283	}
284	
285	/**
286	 * Recursive deep-merge — source overrides target. Plain objects are
287	 * merged structurally; arrays and scalars from source replace target
288	 * outright. Non-mutating.
289	 */
290	export function deepMerge(
291	  target: Record<string, unknown>,
292	  source: Record<string, unknown>,
293	): Record<string, unknown> {
294	  const result: Record<string, unknown> = { ...target };
295	  for (const [k, v] of Object.entries(source)) {
296	    if (isPlainObject(v) && isPlainObject(result[k])) {
297	      result[k] = deepMerge(result[k] as Record<string, unknown>, v);
298	    } else {
299	      result[k] = v;
300	    }
301	  }
302	  return result;
303	}
304	
305	/**
306	 * Discover codexes from upstream yields — any object that has both
307	 * `codexName: string` and `remoteUrl: string` is treated as a codex
308	 * to register in the test guild. Matches the codex-fixture's yield
309	 * shape exactly.
310	 */
311	export interface DiscoveredCodex {
312	  codexName: string;
313	  remoteUrl: string;
314	}
315	
316	export function discoverCodexes(
317	  upstream: Record<string, unknown>,
318	): DiscoveredCodex[] {
319	  const result: DiscoveredCodex[] = [];
320	  for (const value of Object.values(upstream)) {
321	    if (
322	      typeof value === 'object' &&
323	      value !== null &&
324	      !Array.isArray(value)
325	    ) {
326	      const obj = value as Record<string, unknown>;
327	      if (typeof obj.codexName === 'string' && typeof obj.remoteUrl === 'string') {
328	        result.push({ codexName: obj.codexName, remoteUrl: obj.remoteUrl });
329	      }
330	    }
331	  }
332	  return result;
333	}
334	
335	/**
336	 * Run a command via execFile — no shell, predictable arg quoting.
337	 * Throws with stderr on non-zero exit.
338	 */
339	async function exec(
340	  cmd: string,
341	  args: string[],
342	  cwd?: string,
343	): Promise<{ stdout: string; stderr: string }> {
344	  try {
345	    const { stdout, stderr } = await execFile(cmd, args, {
346	      cwd,
347	      maxBuffer: 50 * 1024 * 1024,
348	    });
349	    return { stdout: stdout.trim(), stderr: stderr.trim() };
350	  } catch (err: unknown) {
351	    const e = err as { stderr?: string; message?: string };
352	    throw new Error(
353	      `${cmd} ${args.join(' ')} failed: ${e.stderr || e.message || 'unknown error'}`,
354	    );
355	  }
356	}
357	
358	// ── Setup engine ─────────────────────────────────────────────────────
359	
360	export const guildSetupEngine: EngineDesign = {
361	  id: 'lab.guild-setup',
362	  async run(rawGivens, context: EngineRunContext): Promise<EngineRunResult> {
363	    const givens = validateGivens(rawGivens, 'lab.guild-setup');
364	    const { guildName, guildPath, plugins, config, files, frameworkVersion } = givens;
365	
366	    if (frameworkVersion === undefined) {
367	      throw new Error(
368	        `[lab.guild-setup] framework-injected _trial.frameworkVersion is missing. ` +
369	          `The trial-post tool resolves this from the manifest or the lab-host's ` +
370	          `@shardworks/nexus-core VERSION before stamping the writ; a missing value here ` +
371	          `means the engine was invoked outside the laboratory's phase orchestrators or ` +
372	          `against a writ posted before the resolution change landed.`,
373	      );
374	    }
375	
376	    if (existsSync(guildPath)) {
377	      throw new Error(
378	        `[lab.guild-setup] target dir already exists at ${guildPath}; refusing to clobber. ` +
379	          `Guild name "${guildName}" likely collides with an active trial — pick a unique name.`,
380	      );
381	    }
382	
383	    let initialized = false;
384	
385	    try {
386	      // 1. Bootstrap via npx — runs the trial-pinned `nsg init` against
387	      //    the trial-pinned VERSION. Mirrors how a real user would
388	      //    create a guild (npx-the-CLI). After this, the test guild
389	      //    has @shardworks/nexus installed at the pinned version and
390	      //    its node_modules/.bin/nsg is the version-true CLI.
391	      await mkdir(path.dirname(guildPath), { recursive: true });
392	      await exec('npx', [
393	        '--yes',
394	        '-p',
395	        `@shardworks/nexus@${frameworkVersion}`,
396	        'nsg',
397	        'init',
398	        guildPath,
399	        '--name',
400	        guildName,
401	      ]);
402	      initialized = true;
403	
404	      // From here on, every shellout uses the test guild's local nsg
405	      // — version-matched to the test guild, no dependency on whatever
406	      // CLI happens to be on PATH.
407	      const localNsg = path.join(guildPath, 'node_modules', '.bin', 'nsg');
408	      if (!existsSync(localNsg)) {
409	        throw new Error(
410	          `[lab.guild-setup] expected ${localNsg} after bootstrap but it is missing. ` +
411	            `nsg init's dev-guard skips writing the framework dep and skips npm install when ` +
412	            `running from unbuilt source (VERSION=0.0.0). Pin frameworkVersion to a stable ` +
413	            `spec where the source is built (dist/ exists) — e.g. an exact semver from npm, ` +
414	            `or 'git+file:///path/to/built/repo#<sha>' for a local commit.`,
415	        );
416	      }
417	
418	      // 2. Plugin install. Sequential, not parallel — npm install in the
419	      //    same dir doesn't tolerate concurrency, and order matters when
420	      //    plugins declare peer/optional deps. Per-plugin shellout (vs.
421	      //    a bulk `npm install`) preserves whatever side effects
422	      //    `nsg plugin install` carries beyond the npm install (it
423	      //    updates guild.json's `plugins` array, etc.).
424	      const pluginsResolved: PluginPin[] = [];
425	      for (const pin of plugins) {
426	        const spec = `${pin.name}@${pin.version}`;
427	        await exec(localNsg, ['--guild-root', guildPath, 'plugin', 'install', spec]);
428	        pluginsResolved.push(pin);
429	      }
430	
431	      // 3. Codex registration from upstream.
432	      const codexesAdded: DiscoveredCodex[] = [];
433	      const discovered = discoverCodexes(context.upstream);
434	      for (const codex of discovered) {
435	        await exec(localNsg, [
436	          '--guild-root',
437	          guildPath,
438	          'codex',
439	          'add',
440	          '--name',
441	          codex.codexName,
442	          '--remote-url',
443	          codex.remoteUrl,
444	        ]);
445	        codexesAdded.push(codex);
446	      }
447	
448	      // 4. Deep-merge config into guild.json.
449	      if (Object.keys(config).length > 0) {
450	        const guildJsonPath = path.join(guildPath, 'guild.json');
451	        const existing = JSON.parse(await readFile(guildJsonPath, 'utf8')) as Record<
452	          string,
453	          unknown
454	        >;
455	        const merged = deepMerge(existing, config);
456	        await writeFile(guildJsonPath, JSON.stringify(merged, null, 2) + '\n');
457	      }
458	
459	      // 5. File copies.
460	      const filesCopied: FileCopy[] = [];
461	      for (const file of files) {
462	        const dest = path.join(guildPath, file.guildPath);
463	        await mkdir(path.dirname(dest), { recursive: true });
464	        await copyFile(file.sourcePath, dest);
465	        filesCopied.push(file);
466	      }
467	
468	      return {
469	        status: 'completed',
470	        yields: {
471	          guildName,
472	          guildPath,
473	          pluginsResolved,
474	          codexesAdded,
475	          filesCopied,
476	        },
477	      };
478	    } catch (err) {
479	      // Best-effort rollback: remove the guild dir if we got far enough
480	      // to create it. This means partial-state is not left behind for
481	      // teardown to clean up — every setup attempt is all-or-nothing.
482	      if (initialized) {
483	        try {
484	          await rm(guildPath, { recursive: true, force: true });
485	        } catch {
486	          // swallow — primary error is what we re-throw
487	        }
488	      }
489	      throw err;
490	    }
491	  },
492	};
493	
494	// ── Teardown engine ──────────────────────────────────────────────────
495	
496	export const guildTeardownEngine: EngineDesign = {
497	  id: 'lab.guild-teardown',
498	  async run(rawGivens, _context: EngineRunContext): Promise<EngineRunResult> {
499	    const { guildName, guildPath } = validateGivens(rawGivens, 'lab.guild-teardown');
500	
501	    // Archive-presence safety check (tightened per c-momkqtn5).
502	    const trialId = resolveTrialIdForTeardown(rawGivens, 'lab.guild-teardown');
503	    await assertArchiveRowExists(trialId, 'lab.guild-teardown', `guild "${guildName}"`);
504	
505	    // rm -rf — tolerant of "doesn't exist".
506	    await rm(guildPath, { recursive: true, force: true });
507	
508	    return {
509	      status: 'completed',
510	      yields: {
511	        removed: true,
512	        guildName,
513	        guildPath,
514	      },
515	    };
516	  },
517	};
