1	/**
2	 * nsg start — guild daemon mode.
3	 *
4	 * Two modes selected by --foreground / -f:
5	 *
6	 * - **Detached (default):** spawns the same `nsg` binary with `--foreground`
7	 *   added, fully detached from this terminal, with stdio piped to
8	 *   `.nexus/logs/daemon.{out,err}`. Returns once startup-sync confirms the
9	 *   tool HTTP server is reachable.
10	 *
11	 * - **Foreground (`--foreground` / `-f`):** the inline daemon loop. Boots the
12	 *   guild, starts the Tool HTTP Server (with a Stacks-backed authorize
13	 *   closure), starts the Oculus, runs the Spider continual crawl loop, writes
14	 *   the pidfile, installs SIGTERM/SIGINT handlers, and blocks forever.
15	 *
16	 * The foreground mode IS the daemon — there is no separate daemon entry
17	 * point. `nsg start` (detached) just re-execs itself with --foreground.
18	 *
19	 * The pidfile lives at `.nexus/daemon.pid` relative to the guild home.
20	 * See: docs/architecture/detached-sessions.md, .scratch/nsg-daemon-mode-brief.md
21	 */
22	
23	import fs from 'node:fs';
24	import path from 'node:path';
25	import { spawn } from 'node:child_process';
26	
27	import { z } from 'zod';
28	import { tool } from '@shardworks/tools-apparatus';
29	import type { InstrumentariumApi } from '@shardworks/tools-apparatus';
30	import {
31	  guild,
32	  isProcessAlive,
33	  readPidFile,
34	  tryUnlink,
35	} from '@shardworks/nexus-core';
36	
37	import { getStartedGuild } from '../started-guild.ts';
38	
39	// ── Local apparatus interface shims ──────────────────────────────────
40	//
41	// The CLI package deliberately does not depend on the spider, oculus,
42	// animator, or stacks plugin packages. We declare the minimum interfaces
43	// we need here and look them up via guild().apparatus<T>(name).
44	
45	interface OculusApiLike {
46	  port(): number;
47	  startServer(): Promise<void>;
48	  stopServer(): Promise<void>;
49	}
50	
51	interface SpiderApiLike {
52	  crawl(): Promise<unknown>;
53	}
54	
55	interface SpiderConfigLike {
56	  pollIntervalMs?: number;
57	}
58	
59	interface SessionDocLike {
60	  id: string;
61	  status:
62	    | 'pending'
63	    | 'running'
64	    | 'completed'
65	    | 'failed'
66	    | 'timeout'
67	    | 'cancelled'
68	    | 'rate-limited';
69	  authorizedTools?: string[];
70	}
71	
72	interface BookLike<T> {
73	  get(id: string): Promise<T | undefined>;
74	}
75	
76	interface StacksApiLike {
77	  book<T>(plugin: string, name: string): BookLike<T>;
78	}
79	
80	// ── Filesystem layout helpers ────────────────────────────────────────
81	
82	function paths(home: string): {
83	  nexusDir: string;
84	  pidFile: string;
85	  logsDir: string;
86	  outLog: string;
87	  errLog: string;
88	} {
89	  const nexusDir = path.join(home, '.nexus');
90	  return {
91	    nexusDir,
92	    pidFile: path.join(nexusDir, 'daemon.pid'),
93	    logsDir: path.join(nexusDir, 'logs'),
94	    outLog: path.join(nexusDir, 'logs', 'daemon.out'),
95	    errLog: path.join(nexusDir, 'logs', 'daemon.err'),
96	  };
97	}
98	
99	function tailFile(file: string, lines: number): string {
100	  try {
101	    const content = fs.readFileSync(file, 'utf-8');
102	    const all = content.split('\n');
103	    return all.slice(-lines).join('\n');
104	  } catch {
105	    return '';
106	  }
107	}
108	
109	// ── Detached mode — spawn self with --foreground ─────────────────────
110	
111	async function startDetached(home: string): Promise<string> {
112	  const p = paths(home);
113	
114	  // Idempotency: already-running check.
115	  const existing = readPidFile(p.pidFile);
116	  if (existing && isProcessAlive(existing)) {
117	    return `Guild daemon already running (pid: ${existing})`;
118	  }
119	  if (existing && !isProcessAlive(existing)) {
120	    tryUnlink(p.pidFile);
121	  }
122	
123	  fs.mkdirSync(p.logsDir, { recursive: true });
124	
125	  const outFd = fs.openSync(p.outLog, 'a');
126	  const errFd = fs.openSync(p.errLog, 'a');
127	
128	  // Re-exec the same nsg entry point with --foreground appended.
129	  // process.execPath is node, process.argv[1] is the cli.ts (or compiled
130	  // cli.js) entry — same one Commander dispatched us from.
131	  const nodeArgs = process.execArgv.slice();
132	  const cliEntry = process.argv[1];
133	
134	  const child = spawn(
135	    process.execPath,
136	    [...nodeArgs, cliEntry, 'start', '--foreground', '--guild-root', home],
137	    {
138	      detached: true,
139	      stdio: ['ignore', outFd, errFd],
140	      cwd: home,
141	      env: process.env,
142	    },
143	  );
144	
145	  child.unref();
146	
147	  // Startup sync: poll for pidfile existence + tool server reachability.
148	  const deadline = Date.now() + 10_000;
149	  let lastError = '';
150	  while (Date.now() < deadline) {
151	    const pid = readPidFile(p.pidFile);
152	    if (pid && isProcessAlive(pid)) {
153	      const reached = await pingToolServer(home);
154	      if (reached.ok) {
155	        const oculusUrl = await guessOculusUrl(home);
156	        return [
157	          `Guild daemon started (pid: ${pid})`,
158	          `  Tool HTTP Server:  ${reached.url}`,
159	          `  Oculus:            ${oculusUrl ?? '(starting)'}`,
160	          `  Spider:            crawling (continual mode)`,
161	          `  Logs:              ${path.relative(home, p.outLog)}, ${path.relative(home, p.errLog)}`,
162	        ].join('\n');
163	      }
164	      lastError = reached.error;
165	    }
166	    await new Promise((r) => setTimeout(r, 250));
167	  }
168	
169	  // Startup failed. Tail the err log to help debugging.
170	  const tail = tailFile(p.errLog, 20);
171	  const msg = [
172	    'Guild daemon failed to start within 10s.',
173	    lastError ? `Last error: ${lastError}` : '',
174	    tail ? `\n--- last 20 lines of ${path.relative(home, p.errLog)} ---\n${tail}` : '',
175	  ].filter(Boolean).join('\n');
176	  throw new Error(msg);
177	}
178	
179	async function pingToolServer(
180	  home: string,
181	): Promise<{ ok: true; url: string } | { ok: false; error: string }> {
182	  // Best-effort port discovery — read guild.json tools.serverPort if present.
183	  const port = readToolServerPort(home);
184	  const url = `http://127.0.0.1:${port}`;
185	  try {
186	    const res = await fetch(`${url}/api/tools/list`);
187	    if (res.ok) return { ok: true, url };
188	    return { ok: false, error: `HTTP ${res.status}` };
189	  } catch (err) {
190	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
191	  }
192	}
193	
194	function readToolServerPort(home: string): number {
195	  try {
196	    const raw = fs.readFileSync(path.join(home, 'guild.json'), 'utf-8');
197	    const cfg = JSON.parse(raw) as { tools?: { serverPort?: number } };
198	    return cfg.tools?.serverPort ?? 7471;
199	  } catch {
200	    return 7471;
201	  }
202	}
203	
204	async function guessOculusUrl(home: string): Promise<string | null> {
205	  try {
206	    const raw = fs.readFileSync(path.join(home, 'guild.json'), 'utf-8');
207	    const cfg = JSON.parse(raw) as { oculus?: { port?: number } };
208	    const port = cfg.oculus?.port ?? 7470;
209	    return `http://127.0.0.1:${port}`;
210	  } catch {
211	    return null;
212	  }
213	}
214	
215	// ── Foreground mode — the inline daemon loop ────────────────────────
216	
217	async function startForeground(home: string): Promise<never> {
218	  const p = paths(home);
219	
220	  // Idempotency: refuse to double-start.
221	  const existing = readPidFile(p.pidFile);
222	  if (existing && isProcessAlive(existing)) {
223	    throw new Error(`Guild daemon already running (pid: ${existing})`);
224	  }
225	  if (existing) tryUnlink(p.pidFile);
226	
227	  fs.mkdirSync(p.nexusDir, { recursive: true });
228	
229	  // The guild is already booted by program.ts before any tool handler runs.
230	  const g = guild();
231	
232	  // Build the Stacks-backed authorize closure for the tool server.
233	  // Looks up the session by id and checks its authorizedTools list.
234	  const stacks = g.apparatus<StacksApiLike>('stacks');
235	  const sessionsBook = stacks.book<SessionDocLike>('animator', 'sessions');
236	  const authorize = async (sessionId: string, toolName: string): Promise<boolean> => {
237	    const doc = await sessionsBook.get(sessionId);
238	    if (!doc) return false;
239	    if (doc.status !== 'pending' && doc.status !== 'running') return false;
240	    return doc.authorizedTools?.includes(toolName) ?? false;
241	  };
242	
243	  // Start the Tool HTTP Server.
244	  const tools = g.apparatus<InstrumentariumApi>('tools');
245	  const toolServer = await tools.startToolServer({ authorize });
246	  console.log(`[daemon] Tool HTTP Server listening at ${toolServer.url}`);
247	
248	  // Start the Oculus HTTP server (best-effort — only if installed).
249	  let oculusUrl: string | null = null;
250	  try {
251	    const oculus = g.apparatus<OculusApiLike>('oculus');
252	    await oculus.startServer();
253	    oculusUrl = `http://127.0.0.1:${oculus.port()}`;
254	    console.log(`[daemon] Oculus listening at ${oculusUrl}`);
255	  } catch {
256	    console.warn('[daemon] Oculus not installed — skipping');
257	  }
258	
259	  // Write the pidfile now that the servers are up.
260	  fs.writeFileSync(p.pidFile, String(process.pid), 'utf-8');
261	
262	  // ── Shutdown wiring ────────────────────────────────────────────────
263	  //
264	  // Teardown order on SIGTERM/SIGINT:
265	  //   1. Flip `spiderStop` so the crawl loop exits at its next yield.
266	  //   2. Close the tool HTTP server (D7: the daemon owns this handle —
267	  //      it is returned by tools.startToolServer() rather than wired
268	  //      into the apparatus's stop()).
269	  //   3. Call guildInstance.shutdown(), which fires guild:shutdown,
270	  //      walks the started apparatus list in reverse topological
271	  //      order calling each `stop()` — including Oculus's, so the
272	  //      explicit oculus.stopServer() call that used to live here is
273	  //      now redundant and removed.
274	  //   4. Unlink the pidfile and process.exit(0).
275	  //
276	  // shutdown() is itself idempotent (D4), so the local "first signal
277	  // wins" guard is no longer load-bearing for double-fire safety; we
278	  // keep `spiderStop` local because the crawl loop reads it directly.
279	
280	  const startedGuild = getStartedGuild();
281	  let spiderStop = false;
282	
283	  const shutdown = async (signal: string) => {
284	    console.log(`[daemon] ${signal} received — shutting down...`);
285	
286	    spiderStop = true;
287	    try {
288	      await toolServer.close();
289	    } catch (err) {
290	      console.warn(`[daemon] tool server close failed: ${err instanceof Error ? err.message : err}`);
291	    }
292	
293	    if (startedGuild) {
294	      try {
295	        await startedGuild.shutdown();
296	      } catch (err) {
297	        // shutdown() throws an aggregate when one or more apparatus
298	        // stop()s fail. Surface it but still proceed with pidfile
299	        // cleanup and process exit — partial teardown is better than
300	        // a stuck process.
301	        console.warn(
302	          `[daemon] guild shutdown reported failures: ${err instanceof Error ? err.message : err}`,
303	        );
304	      }
305	    } else {
306	      // No StartedGuild reference — program.ts never deposited one,
307	      // which means createGuild() failed during startup. Nothing to
308	      // tear down.
309	      console.warn(
310	        '[daemon] no StartedGuild reference — skipping apparatus stop() pass',
311	      );
312	    }
313	
314	    tryUnlink(p.pidFile);
315	    console.log('[daemon] stopped');
316	    // D13: explicit exit. The crawl loop and other in-flight timers
317	    // may keep the event loop alive even after apparatus stops; force
318	    // exit to avoid hangs.
319	    process.exit(0);
320	  };
321	
322	  process.on('SIGTERM', () => { void shutdown('SIGTERM'); });
323	  process.on('SIGINT', () => { void shutdown('SIGINT'); });
324	
325	  console.log('[daemon] Guild daemon ready');
326	  console.log(`  Tool HTTP Server:  ${toolServer.url}`);
327	  if (oculusUrl) console.log(`  Oculus:            ${oculusUrl}`);
328	  console.log(`  Spider:            crawling (continual mode)`);
329	  console.log(`  Pidfile:           ${path.relative(home, p.pidFile)}`);
330	
331	  // ── Spider continual crawl loop ────────────────────────────────────
332	  //
333	  // This is what keeps the daemon alive. If the Spider isn't installed,
334	  // we still run a sleep loop so the tool/oculus servers stay up.
335	  //
336	  // Two loop-body cases:
337	  //
338	  // 1. Idle return (null). Spider had nothing dispatchable this tick —
339	  //    either the queue is empty, or every candidate was gated on
340	  //    non-terminal blockers. Sleep intervalMs before asking again.
341	  //
342	  // 2. Progress return (any non-null CrawlResult). Work happened this
343	  //    tick. Yield one macrotask via setImmediate so HTTP/timer
344	  //    handlers run between progress ticks (microtask-only awaits on
345	  //    steady work would otherwise starve them).
346	  //
347	  // Mirror of the fix in packages/plugins/spider/src/tools/crawl-continual.ts
348	  // (both loops exist independently and must be kept in sync).
349	
350	  let spider: SpiderApiLike | null = null;
351	  let intervalMs = 5000;
352	  try {
353	    spider = g.apparatus<SpiderApiLike>('spider');
354	    const spiderCfg = (g.guildConfig() as { spider?: SpiderConfigLike }).spider ?? {};
355	    intervalMs = spiderCfg.pollIntervalMs ?? 5000;
356	  } catch {
357	    console.warn('[daemon] Spider not installed — running idle (servers only)');
358	  }
359	
360	  while (!spiderStop) {
361	    if (spider) {
362	      try {
363	        const result = await spider.crawl();
364	        if (result === null) {
365	          // Idle: nothing dispatchable this tick. Sleep the full interval.
366	          await new Promise((r) => setTimeout(r, intervalMs));
367	        } else {
368	          // Genuine progress: yield one macrotask so HTTP handlers and
369	          // timers aren't starved by microtask-only awaits on steady work.
370	          await new Promise<void>((r) => setImmediate(r));
371	        }
372	      } catch (err) {
373	        console.error(`[daemon] crawl() error: ${err instanceof Error ? err.message : err}`);
374	        await new Promise((r) => setTimeout(r, intervalMs));
375	      }
376	    } else {
377	      await new Promise((r) => setTimeout(r, intervalMs));
378	    }
379	  }
380	
381	  // Unreachable — shutdown() exits the process.
382	  return new Promise<never>(() => {});
383	}
384	
385	// ── Tool definition ──────────────────────────────────────────────────
386	
387	export default tool({
388	  name: 'start',
389	  description: 'Start the guild daemon (tool server + oculus + spider crawl loop)',
390	  callableBy: ['patron'],
391	  params: {
392	    foreground: z
393	      .boolean()
394	      .optional()
395	      .describe('Run in foreground (the inline daemon loop). Default: detached.'),
396	  },
397	  handler: async (params) => {
398	    // The guild is booted by program.ts before this handler runs, so the
399	    // singleton already knows the home directory.
400	    let home: string;
401	    try {
402	      home = guild().home;
403	    } catch {
404	      throw new Error('Not inside a guild. Run `nsg init` to create one first.');
405	    }
406	
407	    if (params.foreground) {
408	      await startForeground(home);
409	      // startForeground never returns under normal operation.
410	      return '';
411	    }
412	
413	    return startDetached(home);
414	  },
415	});
