  engines: [
    {
      id: 'draft',
      designId: 'draft',
      givens: { writ: '${writ}' },
    },
    {
      id: 'implement',
      designId: 'implement',
      upstream: ['draft'],
      givens: { writ: '${writ}', role: '${vars.role}' },
    },
    {
      id: 'review',
      designId: 'review',
      upstream: ['implement'],
      givens: {
        writ: '${writ}',
        role: 'reviewer',
        buildCommand: '${vars.buildCommand}',
        testCommand: '${vars.testCommand}',
      },
    },
    {
      id: 'revise',
      designId: 'revise',
      upstream: ['review'],
      givens: { writ: '${writ}', role: '${vars.role}' },
    },
    {
      id: 'seal',
      designId: 'seal',
      upstream: ['revise'],
      givens: {},
    },
  ],
  resolutionEngine: 'seal',
};

